var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"빈 자리 아무데나 앉아. 주문은 뭘로?","JPN":"空いてるとこに座ってくれ。ご注文は？","ENG":"Take any seat you want. What would you like?","TWN":"空位都可以坐，要點什麼？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"뭘 묻고 그러나. 당연히 <color=#ffd34c>스페셜 런치</color>지.","JPN":"聞くまでもないだろう。当然<color=#ffd34c>スペシャルランチ</color>だ。","ENG":"Why do you ask? It’s the <color=#ffd34c>Special Lunch Set</color>, obviously.","TWN":"有什麼好問的，照舊，<color=#ffd34c>特色午餐</color>。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"하아. 턱수염이었어?","JPN":"はあ、顎ひげだったか。","ENG":"Oh, it’s you, Mr. Goatee.","TWN":"哀，是大鬍子喔？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"이 정도 단골이면 <color=#ffd34c>마크 핀리</color>라는 이름이 있다는 것 정도는 기억해주면 좋겠군.","JPN":"常連なんだから、<color=#ffd34c>マーク・フィンリー</color>という名前くらいは覚えてほしいがな。","ENG":"Won’t you please try to remember your regular's name? My name is <color=#ffd34c>Mark Finley</color>.","TWN":"我這麼常來，起碼該記一下常客的名字叫<color=#ffd34c>馬克·芬利</color>吧。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"응, 턱수염. 자리에 앉기나 해. 출입구 막지 말고.","JPN":"うん、顎ひげ。入口を塞ぐな、席につけ。","ENG":"Okay, Goatee. Have a seat. You’re blocking the entrance.","TWN":"喔。大鬍子，找個位子坐，別擋在門口。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"오늘은…… 그래. 이 자리가 좋겠군.","JPN":"今日は……そうだな、ここが良さそうだな。","ENG":"Okay... I’ll be sitting here today.","TWN":"我今天要坐……就坐這裡吧。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"적당히 구석이고, 햇빛도 적당히 비춰주고.","JPN":"適度に隅で、日差しもちょうどいい具合に差し込んでいる。","ENG":"It’s cozy, right here in the sun.","TWN":"在不起眼的角落，也不會曬到太多太陽。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"여기 스페셜 런치 도착이요♪","JPN":"お待たせしました！　スペシャルランチです♪","ENG":"Here is your Special Lunch Set! ♪","TWN":"這是你點的特色午餐♪"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"호오! 음식이 이렇게 빨리 나왔다는 건 날 위해 미리 준비했다는 얘긴가?","JPN":"ほう！　頼んだ料理がこんなに早く提供されるとは、私のために事前に準備してくれたのか？","ENG":"Oh, that was very fast. Were you waiting for me?","TWN":"喔喔！這麼快就端出來，應該是事前就先替我預備好的吧？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"환상을 깨서 미안하지만, 우연히 조리되어 있던 거야. 우연히.","JPN":"期待を裏切って悪いが、たまたま調理してたんだ。たまたまな。","ENG":"I’d hate to burst your bubble, but the dish just happened to be ready. It was a coincidence.","TWN":"做你的夢，不好意思喔，只是湊巧而已。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"응? 이거 시간 맞춰 준비해두라고 라우라 네가…….","JPN":"ん？　これって確か、時間ピッタリに用意しておけって、ラウラが……","ENG":"Huh? But you asked me to cook it in time...","TWN":"嗯？蘿拉，不是你叫我抓準時間準備……"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"턱수염이 우리 카페에 1초라도 더 있는 꼴을 못 보겠어서 그랬다, 왜.","JPN":"なんだ？　顎ひげがうちのカフェから1秒でも早く出て行ってもらおうと思ったからだ。","ENG":"That’s because I didn’t want to see that hairy moron in my shop for too long.","TWN":"因為我想要大鬍子趕快吃一吃趕快滾啦，怎樣！"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"후후후. 솔직하지 못한 점장님이로구만.","JPN":"フフフ。素直じゃない店長だな。","ENG":"Haha, you really speak your mind, don't you?","TWN":"呵呵呵，真是傲嬌的店長。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CAT_STREGA_NULL_NULL","text":{"KOREA":"냐옹~","JPN":"にゃあ～。","ENG":"Meow.","TWN":"喵喵～"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"플루토, 테이블에서 뭐하는 짓이야? 빨리 안 내려와?","JPN":"プルートー、テーブルの上で何してるんだ？　早く降りてこい。","ENG":"Pluto, you’re not supposed to be on the table! Get down!","TWN":"布魯托，你在桌子上幹嘛？還不快下來？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"오! 괜찮네. 드디어 이 명물 고양이의 실물을 가까이에서 영접하는군!","JPN":"おお！　これは嬉しいな。やっとこの名物ネコ君の実物が見られたな！","ENG":"Oh, it’s okay! I finally get to see the famous kitty up close!","TWN":"沒關係！終於可以近距離目睹人氣店貓本尊！"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"뭔가 착각한 거 아냐? 플루토는 그냥 고양이야.","JPN":"何か勘違いしてないか？　プルートーはただのネコだぞ？","ENG":"You must be mistaken. Pluto is just an ordinary cat.","TWN":"你是不是有什麼誤會？布魯托就只是一隻普通的貓而已。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CAT_STREGA_NULL_NULL","text":{"KOREA":"냐아옹, 냐옹?","JPN":"にゃああ、にゃあ？","ENG":"Meow, meow?","TWN":"喵，喵喵？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};